package com.trademaster.ims.mobile.reviews.model;
import jakarta.persistence.*;import java.time.Instant;
@Entity @Table(name="customer_product_reviews",indexes={@Index(name="idx_review_product_status",columnList="product_id,status"),@Index(name="idx_review_account",columnList="customer_account_id"),@Index(name="idx_review_number",columnList="review_number",unique=true)},uniqueConstraints=@UniqueConstraint(name="uk_review_order_item_product",columnNames={"customer_account_id","order_item_id","product_id"}))
public class CustomerProductReview{public enum Status{PENDING,APPROVED,REJECTED}@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="review_number",nullable=false,unique=true,length=48)private String reviewNumber;@Column(name="product_id",nullable=false)private Long productId;@Column(name="customer_account_id",nullable=false)private Long accountId;@Column(name="order_number",nullable=false,length=60)private String orderNumber;@Column(name="order_item_id",nullable=false)private Long orderItemId;@Column(nullable=false)private int rating;@Column(length=120)private String title;@Column(nullable=false,length=1000)private String comment;@Enumerated(EnumType.STRING)@Column(nullable=false,length=20)private Status status=Status.APPROVED;@Column(name="moderation_note",length=500)private String moderationNote;@Column(name="created_at",nullable=false,updatable=false)private Instant createdAt;@Column(name="updated_at",nullable=false)private Instant updatedAt;@Version private Long version;@PrePersist void c(){createdAt=updatedAt=Instant.now();}@PreUpdate void u(){updatedAt=Instant.now();}
public Long getId(){return id;}public String getReviewNumber(){return reviewNumber;}public void setReviewNumber(String v){reviewNumber=v;}public Long getProductId(){return productId;}public void setProductId(Long v){productId=v;}public Long getAccountId(){return accountId;}public void setAccountId(Long v){accountId=v;}public String getOrderNumber(){return orderNumber;}public void setOrderNumber(String v){orderNumber=v;}public Long getOrderItemId(){return orderItemId;}public void setOrderItemId(Long v){orderItemId=v;}public int getRating(){return rating;}public void setRating(int v){rating=v;}public String getTitle(){return title;}public void setTitle(String v){title=v;}public String getComment(){return comment;}public void setComment(String v){comment=v;}public Status getStatus(){return status;}public void setStatus(Status v){status=v;}public String getModerationNote(){return moderationNote;}public void setModerationNote(String v){moderationNote=v;}public Instant getCreatedAt(){return createdAt;}public Instant getUpdatedAt(){return updatedAt;}public Long getVersion(){return version;}}